UPDATE TAB_TENANT
SET I_STATUS = #{status},
    DT_UPDATE_TIME = NOW(),
    S_UPDATE_USER = #{operator}
WHERE S_ID = #{sId}

UPDATE TAB_TENANT
SET D_EXPIRE_DATE = #{expireDate},
    DT_UPDATE_TIME = NOW(),
    S_UPDATE_USER = #{operator}
WHERE S_ID = #{sId}

UPDATE TAB_TENANT
SET I_AI_ENABLED = #{aiEnabled},
    DT_UPDATE_TIME = NOW(),
    S_UPDATE_USER = #{operator}
WHERE S_ID = #{sId}
